// ─── Sub-region system ─────────────────────────
// 11 sub-regions mapped to 5 continent SVG groups.
// Events use sub-regions; the map highlights the parent continent.

export const SUB_REGIONS = [
    'Europe', 'Middle East',
    'North Africa', 'West Africa', 'East Africa', 'Southern Africa',
    'South Asia', 'East Asia',
    'North America', 'Central America', 'South America',
];

// Map sub-region → continent SVG group name
export const REGION_TO_CONTINENT = {
    'Europe': 'Europe',
    'Middle East': 'Middle East',
    'North Africa': 'Africa',
    'West Africa': 'Africa',
    'East Africa': 'Africa',
    'Southern Africa': 'Africa',
    'South Asia': 'Asia',
    'East Asia': 'Asia',
    'North America': 'Americas',
    'Central America': 'Americas',
    'South America': 'Americas',
};

// Approximate SVG centers for each sub-region (Natural Earth I projection)
export const REGION_CENTERS = {
    "Europe": { x: 429, y: 124 },
    "Middle East": { x: 494, y: 174 },
    "North Africa": { x: 421, y: 179 },
    "West Africa": { x: 396, y: 230 },
    "East Africa": { x: 476, y: 255 },
    "Southern Africa": { x: 453, y: 313 },
    "South Asia": { x: 566, y: 194 },
    "East Asia": { x: 625, y: 161 },
    "North America": { x: 204, y: 136 },
    "Central America": { x: 210, y: 212 },
    "South America": { x: 275, y: 288 },
};

// Normalize any legacy or variant region name → canonical sub-region
export function normalizeRegion(region) {
    if (region === 'Africa') return 'East Africa';       // legacy fallback
    if (region === 'Asia') return 'East Asia';            // legacy fallback
    if (region === 'Americas') return 'North America';    // legacy fallback
    return region;
}

// Sub-region → continent for map SVG group highlighting
export function regionToContinent(region) {
    return REGION_TO_CONTINENT[region] || REGION_TO_CONTINENT[normalizeRegion(region)] || 'Europe';
}

// Natural Earth I projection: lat/lng → SVG coordinates (800x500 viewBox)
// Uses the same polynomial coefficients as d3-geo's geoNaturalEarth1.
const PROJ_SCALE = 143.3071;
const PROJ_TX = 400;
const PROJ_TY = 250;
const A0 = 0.8707, A1 = -0.131979, A2 = -0.013791, A3 = 0.003971, A4 = -0.001529;
const B0 = 1.007226, B1 = 0.015085, B2 = -0.044475, B3 = 0.028874, B4 = -0.005916;
const DEG2RAD = Math.PI / 180;

export function projectToSVG(lat, lng, region) {
    // Handle the lat:0 lng:0 edge case (f35 Circumnavigation, tagged "Europe")
    if (lat === 0 && lng === 0 && region) {
        const center = REGION_CENTERS[region] || REGION_CENTERS[normalizeRegion(region)];
        if (center) return center;
    }
    const lambda = lng * DEG2RAD;
    const phi = lat * DEG2RAD;
    const phi2 = phi * phi;
    const phi4 = phi2 * phi2;
    const rawX = lambda * (A0 + phi2 * (A1 + phi2 * (A2 + phi4 * (A3 + phi2 * A4))));
    const rawY = phi * (B0 + phi2 * (B1 + phi2 * (B2 + phi4 * (B3 + phi2 * B4))));
    return {
        x: PROJ_SCALE * rawX + PROJ_TX,
        y: -PROJ_SCALE * rawY + PROJ_TY,
    };
}
